#include <meta>
#include <print>

int speed = 100;
struct Point { int x, y; };

namespace physics {}

int main() {
    // ^^ captures an entity and returns a constexpr prvalue of type std::meta::info
    constexpr std::meta::info r_type = ^^int;      // type
    constexpr std::meta::info r_var  = ^^speed;    // variable
    constexpr std::meta::info r_user = ^^Point;    // user-defined type

    // std::meta::is_type: true only for types
    std::print("is_type(^^int)   = {}\n", std::meta::is_type(r_type));
    std::print("is_type(^^speed) = {}\n", std::meta::is_type(r_var));
    std::print("is_type(^^Point) = {}\n", std::meta::is_type(r_user));

    // std::meta::is_variable: true for variables
    std::print("is_variable(^^speed) = {}\n", std::meta::is_variable(r_var));
}

#include <meta>
#include <print>
#include <string_view>

double area(int w, int h) { return w * h; }
int max_count = 256;

consteval std::string_view name(std::meta::info r) {
    return std::meta::identifier_of(r);
}

consteval bool same_type(std::meta::info a, std::meta::info b) {
    return a == b;
}

int main() {
    constexpr auto r_area      = ^^area;
    constexpr auto r_max_count = ^^max_count;

    // identifier_of: declared name of the entity
    std::print("name(^^area)      = {}\n", name(r_area));
    std::print("name(^^max_count) = {}\n", name(r_max_count));

    // is_function
    std::print("is_function(^^area)      = {}\n", std::meta::is_function(r_area));
    std::print("is_function(^^max_count) = {}\n", std::meta::is_function(r_max_count));

    // type_of: returns std::meta::info for the entity's type
    // == comparison is also consteval-only, so wrap in a consteval function
    constexpr bool type_is_int = same_type(std::meta::type_of(r_max_count), ^^int);
    std::print("type_of(^^max_count) == ^^int: {}\n", type_is_int);

    // == compares by entity identity
    constexpr bool same = same_type(r_area, ^^area);
    constexpr bool diff = same_type(r_area, r_max_count);
    std::print("^^area == ^^area:      {}\n", same);
    std::print("^^area == ^^max_count: {}\n", diff);
}

