#include <meta>
#include <print>

int counter = 0;

int side_effect() {
    ++counter;
    return 42;
}

int main() {
    // ^^ reflects the entity; it does NOT call the function
    constexpr auto r = ^^side_effect;  // side_effect() is NOT called

    std::print("is_function(^^side_effect) = {}\n",
               std::meta::is_function(r));
    std::print("counter after ^^ = {}\n", counter);  // 0: no call happened

    // For comparison: an actual call increments counter
    int val = side_effect();
    std::print("side_effect() = {}\n", val);
    std::print("counter after call = {}\n", counter);  // 1
}

