    std::cout << sizeof(typename [:r:]) << "\n";

    // 3. static_cast via type splice
    int n = 7;
    auto f = static_cast<typename [:r:]>(n);
    std::cout << f << "\n";

    // 4. Roundtrip identity check
    constexpr bool same = std::is_same_v<typename [:^^int:], int>;
    std::cout << same << "\n";

    return 0;
}

#include <meta>
#include <iostream>

enum Color { Red = 10, Green = 20, Blue = 30 };
constexpr int kMax = 255;

int main() {
    // Splice an enumerator as a value
    constexpr auto r_green = ^^Color::Green;
    std::cout << (int)[:r_green:] << "\n";   // 20

    // Splice a constexpr variable — lvalue
    constexpr auto r_max = ^^kMax;
    std::cout << [:r_max:] << "\n";           // 255

    // Take address: [:r:] is an lvalue
    const int* p = &[:r_max:];
    std::cout << *p << "\n";                   // 255

    return 0;
}

