#include <meta>
#include <iostream>
#include <string_view>
#include <optional>

enum class Status { Pending, Running, Done, Failed };

std::string_view to_string(Status s) {
    template for (constexpr auto e :
                  std::define_static_array(std::meta::enumerators_of(^^Status))) {
        if ([:e:] == s) return std::meta::identifier_of(e);
    }
    return "unknown";
}

std::optional<Status> from_string(std::string_view name) {
    template for (constexpr auto e :
                  std::define_static_array(std::meta::enumerators_of(^^Status))) {
        if (std::meta::identifier_of(e) == name) return [:e:];
    }
    return std::nullopt;
}

int main() {
    for (auto s : {Status::Pending, Status::Running, Status::Done, Status::Failed})
        std::cout << to_string(s) << "\n";

    auto r1 = from_string("Done");
    std::cout << "Done -> " << (r1 ? to_string(*r1) : "not found") << "\n";

    auto r2 = from_string("Cancelled");
    std::cout << "Cancelled -> " << (r2 ? to_string(*r2) : "not found") << "\n";
}

