    for (auto m : std::meta::nonstatic_data_members_of(
                      ^^Config, std::meta::access_context::unchecked())) {
        // Each field T -> std::optional<T>
        auto opt_type = std::meta::substitute(
            ^^std::optional, {std::meta::type_of(m)});
        fields.push_back(std::meta::data_member_spec(
            opt_type, {.name = std::meta::identifier_of(m)}));
    }
    std::meta::define_aggregate(^^ConfigPatch, fields);
