#include <meta>
#include <print>

// Tag type: serialization marker
struct Serialize {};

struct User {
    [[=Serialize{}]] std::string_view name;
    [[=Serialize{}]] int age;
    std::string_view password_hash;  // intentionally not annotated
};

// Does this member carry a Serialize annotation?
consteval bool is_serializable(std::meta::info m) {
    for (auto ann : std::meta::annotations_of(m))
        if (std::meta::type_of(ann) == ^^Serialize) return true;
    return false;
}

template <class T>
void list_serializable_fields() {
    std::println("Serializable fields of {}:",
                 std::meta::display_string_of(^^T));
    constexpr auto fields = std::define_static_array(
        std::meta::nonstatic_data_members_of(^^T,
            std::meta::access_context::unchecked())
    );
    template for (constexpr auto m : fields) {
        if constexpr (is_serializable(m)) {
            std::println("  + {}", std::meta::identifier_of(m));
        } else {
            std::println("  - {} (skipped)", std::meta::identifier_of(m));
        }
    }
}

int main() {
    list_serializable_fields<User>();
}

#include <meta>
#include <print>

// Annotation carrying data: a structural type with two int fields
struct Range {
    int min;
    int max;
};

struct Config {
    [[=Range{0, 100}]]   int brightness;
    [[=Range{1, 16}]]    int threads;
    [[=Range{0, 65535}]] int port;
    std::string_view name;  // no annotation
};

consteval bool has_range(std::meta::info m) {
    for (auto ann : std::meta::annotations_of(m))
        if (std::meta::type_of(ann) == ^^Range) return true;
    return false;
}

consteval Range get_range(std::meta::info m) {
    for (auto ann : std::meta::annotations_of(m))
        if (std::meta::type_of(ann) == ^^Range)
            return std::meta::extract<Range>(ann);
    return {0, 0};
}

template <class T>
void print_constraints() {
    std::println("Constraints for {}:", std::meta::display_string_of(^^T));
    constexpr auto fields = std::define_static_array(
        std::meta::nonstatic_data_members_of(^^T,
            std::meta::access_context::unchecked())
    );
    template for (constexpr auto m : fields) {
        if constexpr (has_range(m)) {
            constexpr Range r = get_range(m);
            std::println("  {} in [{}, {}]",
                         std::meta::identifier_of(m), r.min, r.max);
        }
    }
}

int main() {
    print_constraints<Config>();
}

